-- Migration: Fix video lessons to include video_url at top level
-- This ensures the LessonRenderer properly displays embedded YouTube videos

-- Fix Smartwatch Overview lesson (video type) - add video_url at root level
UPDATE lessons SET content_json = '{"video_url": "https://www.youtube.com/watch?v=52L8VP05elU", "sections": [{"title": "Introduction", "content": "In this program you will design and implement a fully functioning smartwatch by combining low level driver development, embedded systems programming, and system-level integration.\n\nYou''ll work on the LilyGo T-Watch 2020 V3, a real commercial smartwatch platform, and write production-style firmware entirely in C and C++: the same languages used in industry for resource-constrained embedded systems.\n\n- C is used for low-level hardware control and communication\n- C++ enables modular design, abstraction, and higher-level application logic\n\nThroughout the program you''ll build your system incrementally using provided training materials, reference implementations, and targeted code examples. These resources are designed to support you without removing the need for engineering decision making.\n\nIf you need help, email support@shortcct.com with your specific questions and a zip file including your project directory. Remember, virtual support is available for 3 months after your product delivery date."}, {"title": "Recommended Background", "content": "This project is designed for students who want hands-on embedded firmware experience. You do not need a lot of experience, but some foundational knowledge is expected.\n\n**Required:**\n- Introductory programming experience in C or C++\n- Comfort with basic programming concepts such as functions, control flow, arrays, and structs\n\n**Helpful:**\n- Introductory exposure to embedded systems\n- Introductory electronics knowledge\n\nIf you find that you are missing some of this background, reach out to us at support@shortcct.com and we can explore options to get you up to speed!"}, {"title": "Industry Alignment", "content": "We analyzed the most in-demand skills across 50+ companies hiring embedded systems engineering interns. Below is how the Smartwatch Project aligns with those skills.\n\n- **Core skills** are fully covered in the base project.\n- **Extendable skills** can be developed through optional project extensions and the design challenge.\n- **Not Covered** indicates skills that are outside the scope of the core project."}, {"title": "Documentation", "content": "Here is the relevant documentation that you will need to use throughout the development of your project:\n\n**Datasheets:**\n- AXP202 Datasheet\n- PCF8563 Datasheet\n- ST7789V Datasheet\n- FT6236U Datasheet\n- BMA423 Datasheet\n\n**Libraries:**\n- TFT_eSPI Library\n- AXP202X_Library\n- BMA423_Library\n\n**Other:**\n- T-Watch Pinout\n- T-Watch Schematic"}, {"title": "Set Up Smartwatch", "content": "To set up PlatformIO, this video by DroneBot Workshop is a great resource. It includes installation steps for Linux, MacOS, and Windows. You can download the latest versions of Python and Visual Studio Code.\n\nOnce you have downloaded PlatformIO on your system, watch the following video to set up your environment for our project.\n\nThe following video shows you how to clone our GitHub repository, `short-circuit-projects/smartwatch`, to VSCode. This tutorial is done on Windows, so it will look different on Linux or MacOS."}], "key_points": ["Work on the LilyGo T-Watch 2020 V3 platform", "Write production-style firmware in C and C++", "Build system incrementally with provided training materials", "Support available at support@shortcct.com for 3 months"], "resources": [{"title": "GitHub Repository", "url": "https://github.com/short-circuit-projects/smartwatch", "type": "github"}]}' WHERE id = 'lesson-t-overview';

-- Fix Ball and Beam Overview lesson (video type) - add video_url at root level
UPDATE lessons SET content_json = '{"video_url": "", "sections": [{"title": "Project Overview", "content": "The Ball and Beam project teaches you to design and implement a closed-loop control system. You will:\n\n1. **Understand the hardware** - 3D printed parts, electronics, and wooden platform\n2. **Learn control theory** - PID control, feedback loops, and system modeling\n3. **Write embedded software** - Real-time control loops in C++\n4. **Test and tune** - Hands-on calibration and performance optimization\n\nThis video provides a complete overview of the project and what you will accomplish.\n\n**Note:** Overview video coming soon."}], "key_points": ["Closed-loop control system implementation", "Combines hardware and software skills", "Real-time embedded programming", "Hands-on testing and tuning"], "resources": []}' WHERE id = 'bb-lesson-t-overview';
